class Board:
    """
    Represents the state of the checkerboard.
    """

    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.init_board()

    def init_board(self):
        # Initialize the board with pieces in their starting positions
        colors = ['B', 'R']
        positions = [(i, j) for i in range(3) for j in range(0, 8, 2)] + [(i, j) for i in range(5, 8) for j in range(1, 9, 2)]

        for color, position in zip(colors * 4, positions):
            self.board[position[0]][position[1]] = Piece(color)

    def print_board(self):
        # Print the current state of the board
        for row in self.board:
            for piece in row:
                if piece is None:
                    print('.', end=' ')
                else:
                    print(piece.symbol, end=' ')
            print()

class Piece:
    """
    Represents a single checker piece (either a regular piece or a king).
    """

    def __init__(self, color):
        self.color = color
        self.is_king = False

    @property
    def symbol(self):
        return 'K' if self.is_king else self.color

    def promote_to_king(self):
        self.is_king = True
