class Player:
    """
    Represents a player with pieces on the board.
    """

    def __init__(self, color):
        self.color = color
        self.pieces = []

    def add_piece(self, piece, position):
        # Add a piece to the player's collection and place it on the board
        piece.is_king = False
        self.pieces.append(piece)
        self.board[position[0]][position[1]] = piece

    def move_piece(self, from_position, to_position):
        # Move a piece from one position to another
        piece = self.board[from_position[0]][from_position[1]]
        if piece and piece.color == self.color:
            self.board[to_position[0]][to_position[1]] = piece
            self.board[from_position[0]][from_position[1]] = None

class Game:
    """
    Manages the game state, including turns and move validation.
    """

    def __init__(self):
        self.board = Board()
        self.players = {'B': Player('B'), 'R': Player('R')}
        self.current_player = self.players['B']

    def play_move(self, from_pos, to_pos):
        # Play a move and switch turns
        if self.is_valid_move(from_pos, to_pos):
            piece = self.board.board[from_pos[0]][from_pos[1]]
            self.board.move_piece(from_pos, to_pos)
            if self.is_promotion(to_pos):
                piece.promote_to_king()
            self.current_player = self.players['R'] if self.current_player == self.players['B'] else self.players['B']

    def is_valid_move(self, from_pos, to_pos):
        # Check if a move is valid
        piece = self.board.board[from_pos[0]][from_pos[1]]
        return (piece and piece.color == self.current_player.color)  # Simplified validation

    def is_promotion(self, pos):
        # Check if a piece should be promoted to a king
        row, col = pos
        return row == 0 and self.current_player.color == 'B' or row == 7 and self.current_player.color == 'R'
